using UnityEngine;

/// <summary>
/// Broto de Vida — drop de chão (inimigos, mundo): cura <see cref="healAmount"/>
/// corações IMEDIATAMENTE ao ser apanhado. Não vai para o inventário — a cura é
/// instantânea, como uma erva apanhada no campo.
///
/// O Broto de Vida que o jogador COMPRA em loja chega ao inventário como
/// ItemData (effectType = CuraInstantanea) e é usado manualmente — ver
/// PlayerItemUser.UseInstantHealItem. A quantidade máxima transportável é
/// configurada em ItemData.maxQuantity do asset correspondente.
/// </summary>
public class BrotoDeVidaPickup : PickupBase
{
    [Header("Broto de Vida")]
    [Tooltip("Corações recuperados instantaneamente ao apanhar este drop.")]
    [Min(1)] public int healAmount = 1;

    public override PickupType Type => PickupType.BrotoDeVida;

    protected override void GrantReward()
    {
        var progress = PlayerProgress.Instance;
        if (progress != null) progress.Heal(healAmount);
    }
}
